nta.declaration:
// Place global declarations here.
clock globalTime;

//R0 = A
clock R0;
const int R0Init = 5;
const int R0Levels = 5;

//R1 = B
clock R1;
const int R1Init = 0;
const int R1Levels = 3;

//Reaction R0 (A) --> R1 (B)
const double k_R0_R1 = 0.004;

template.declaration:
double rateR0() {
	return 0;
}

double boundedRateR0() {
	return 0;
}

double rateR1() {
	double R0_R1_r = k_R0_R1 * (R1Levels - R1) * R0;
	return R0_R1_r;
}

double boundedRateR1() {
	double r = rateR1();
	if (R1 + r > R1Levels) {
		return R1Levels - R1;
	} else if (R1 + r < 0) {
		return -R1;
	}
	return r;
}
